      const ratingStars = document.querySelectorAll('#rating div');
      const selectedRatingSpan = document.getElementById('selected-rating');

      let selectedRating = 0;

      ratingStars.forEach((star, index) => {
        star.addEventListener('click', () => {
          selectedRating = index + 1;
          selectedRatingSpan.textContent = `You selected ${selectedRating} star${selectedRating > 1 ? 's' : ''}`;
        });

        if (index + 1 <= selectedRating) {
          star.setAttribute('aria-label', `Star ${index + 1}`);
          star.setAttribute('aria-current', 'true');
        } else {
          star.setAttribute('aria-label', `Star ${index + 1}`);
          star.setAttribute('aria-current', 'false');
        }
      });

